	t.Setenv("PATH", fakeBin+string(os.PathListSeparator)+os.Getenv("PATH"))

	cfg := config.NewTestConfigForBead(config.TestBeadConfigOpts{
		Model: "gpt-5.4-mini",
	})
	rcfg := cfg.Resolve(config.CLIOverrides{Harness: "codex"})

