package modelsnapshot

import (
	"context"
	"path/filepath"
	"strings"

	"github.com/easel/fizeau/internal/discoverycache"
	"github.com/easel/fizeau/internal/modelcatalog"
)

// AssembleServiceConfigWithOptions assembles a snapshot from the service-owned
// snapshot config adapter and the configured cache root.
func AssembleServiceConfigWithOptions(ctx context.Context, cfg *Config, cat *modelcatalog.Catalog, cacheRoot string, opts AssembleOptions) (ModelSnapshot, error) {
	cache := &discoverycache.Cache{Root: cacheRoot}
	return AssembleWithOptions(ctx, cfg, cat, cache, opts)
}

// DefaultCacheRoot resolves the service snapshot cache root using the same
// environment override contract as the root service facade.
func DefaultCacheRoot(getenv func(string) string, userCacheDir func() (string, error)) (string, error) {
	if override := strings.TrimSpace(getenv("FIZEAU_CACHE_DIR")); override != "" {
		return override, nil
	}
	cacheDir, err := userCacheDir()
	if err != nil {
		return "", err
	}
	return filepath.Join(cacheDir, "fizeau"), nil
}

// Package discoverycache implements the per-source on-disk cache described in
// ADR-012. It provides a two-tier lock + long-lived refresh marker pattern so
// that slow discovery IO (PTY ~30 s, HTTP ~316 ms) never blocks UI reads.
//
// Public surface: Cache.Read, Cache.Refresh, Cache.MaybeRefresh, Cache.Prune.
// The Refresher function is injected; the cache manages single-flight
// deduplication, atomic writes, and crash recovery.
package discoverycache

import (
	"context"
	"errors"
	"io/fs"
	"os"
	"path/filepath"
	"strings"
	"time"

	"golang.org/x/sync/singleflight"
)

const (
	lockAcquisitionTimeout = 100 * time.Millisecond
	lockPollInterval       = 5 * time.Millisecond
	waitPollInterval       = 250 * time.Millisecond
	stalenessMultiplier    = time.Duration(2)
	refreshFailureCooldown = 250 * time.Millisecond
)

// Cache is the root handle. Root is the base directory (e.g. ~/.cache/fizeau).
// Each Cache instance owns one in-process singleflight.Group; a new Cache per
// process is the normal usage.
type Cache struct {
	Root string
	sf   singleflight.Group

	waitForRefreshHook func(Source)
}

// Source describes one cacheable data stream (one file under Root/Tier/Name.json).
type Source struct {
	// Tier is "discovery" or "runtime".
	Tier string
	// Name is the kebab-case source identifier (e.g. "openrouter").
	Name string
	// TTL controls freshness: Read returns Fresh=true when Age < TTL.
	TTL time.Duration
	// RefreshDeadline is the maximum time a refresh is expected to take.
	// Also controls the staleness threshold: 2 × RefreshDeadline.
	RefreshDeadline time.Duration
}

func (s Source) key() string { return s.Tier + "/" + s.Name }

// ReadResult is the output of Cache.Read.
type ReadResult struct {
	// Data is the raw bytes from the cache file; nil if no file exists.
	Data []byte
	// Age is how long ago the data was written (0 if absent).
	Age time.Duration
	// Fresh is true when Age < TTL and Data is non-nil.
	Fresh bool
	// Stale is true when Data is nil or Age >= TTL.
	Stale bool
}

// RefreshState reports the current marker state for a source. It is used by
// higher layers to surface refresh_failed / in-flight diagnostics without
// re-reading raw marker files.
type RefreshState struct {
	InFlight  bool
	Failed    bool
	LastError string
	StartedAt time.Time
	Deadline  time.Time
}

// Refresher is the source-fetch function injected by the caller. The cache
// handles single-flight deduplication, the atomic write, and marker lifecycle.
type Refresher func(ctx context.Context) ([]byte, error)

// Read returns cached data without any IO beyond reading the local file.
// It never blocks on network or PTY. If no cache file exists, Data is nil and
// Stale is true. Stale data is always returned without error; the caller
// decides whether to trigger a background refresh.
func (c *Cache) Read(s Source) (ReadResult, error) {
	path := c.dataPath(s)
	data, err := os.ReadFile(path) // #nosec G304
	if errors.Is(err, os.ErrNotExist) {
		return ReadResult{Stale: true}, nil
	}
	if err != nil {
		return ReadResult{}, err
	}
	info, err := os.Stat(path)
	if err != nil {
		// File was just there; best-effort fallback.
		return ReadResult{Data: data, Stale: true}, nil
	}
	age := time.Since(info.ModTime())
	if age < 0 {
		age = 0
	}
	fresh := age < s.TTL
	return ReadResult{
		Data:  data,
		Age:   age,
		Fresh: fresh,
		Stale: !fresh,
	}, nil
}

// Prune removes data files (and their sidecar lock/marker/tmp files) for
// sources not listed in activeSources. Sources with an active .refreshing
// marker are skipped. Prune acquires the tier-1 lock before removing each
// source's files.
func (c *Cache) Prune(activeSources []Source) error {
	active := make(map[string]bool, len(activeSources))
	for _, s := range activeSources {
		active[s.key()] = true
	}

	return filepath.WalkDir(c.Root, func(path string, d fs.DirEntry, err error) error {
		if err != nil || d.IsDir() {
			return nil
		}
		if !strings.HasSuffix(d.Name(), ".json") {
			return nil
		}
		rel, rerr := filepath.Rel(c.Root, path)
		if rerr != nil {
			return nil
		}
		parts := strings.SplitN(rel, string(filepath.Separator), 2)
		if len(parts) != 2 {
			return nil
		}
		tier := parts[0]
		name := strings.TrimSuffix(parts[1], ".json")
		if strings.ContainsRune(name, filepath.Separator) {
			return nil // nested dir, skip
		}

		if active[tier+"/"+name] {
			return nil
		}

		s := Source{Tier: tier, Name: name}

		// Skip sources with an active refresh in progress.
		m, _ := readMarker(c.markerPath(s))
		if isMarkerActiveForPrune(m) {
			return nil
		}

		release, lerr := c.acquireLock(s)
		if lerr != nil {
			return nil // can't lock; skip this source
		}
		defer release()

		// Re-check under lock.
		m2, _ := readMarker(c.markerPath(s))
		if isMarkerActiveForPrune(m2) {
			return nil
		}

		_ = os.Remove(c.dataPath(s))
		_ = os.Remove(c.markerPath(s))
		_ = os.Remove(c.tmpPath(s))
		return nil
	})
}

// RefreshState reports the current refresh marker status for s.
func (c *Cache) RefreshState(s Source) (RefreshState, error) {
	m, err := readMarker(c.markerPath(s))
	if err != nil || m == nil {
		return RefreshState{}, err
	}
	return RefreshState{
		InFlight:  !isStale(s, m),
		Failed:    strings.TrimSpace(m.LastError) != "",
		LastError: strings.TrimSpace(m.LastError),
		StartedAt: m.StartedAt,
		Deadline:  m.Deadline,
	}, nil
}

// SetWaitForRefreshHookForTesting lets tests observe when Refresh joins an
// already active marker-owned refresh and begins waiting for it to finish.
func (c *Cache) SetWaitForRefreshHookForTesting(h func(Source)) {
	c.waitForRefreshHook = h
}

// ---- internal ---------------------------------------------------------------

type claimResult struct {
	claimed bool
	marker  *refreshMarker
}

// claimRefresh implements Algorithm 1 from ADR-012. Must be called with the
// source directory already created (ensured by refreshAndCommit).
func (c *Cache) claimRefresh(s Source) (claimResult, error) {
	release, err := c.acquireLock(s)
	if err != nil {
		return claimResult{}, err
	}
	defer release()

	existing, _ := readMarker(c.markerPath(s))
	if existing != nil {
		if isStale(s, existing) {
			_ = os.Remove(c.markerPath(s))
		} else {
			return claimResult{claimed: false, marker: existing}, nil
		}
	}

	m := &refreshMarker{
		PID:       os.Getpid(),
		StartedAt: time.Now().UTC(),
		Deadline:  time.Now().UTC().Add(s.RefreshDeadline),
	}
	if werr := writeMarker(c.markerPath(s), m); werr != nil {
		return claimResult{}, werr
	}
	return claimResult{claimed: true}, nil
}

// refreshAndCommit implements Algorithm 2 from ADR-012.
func (c *Cache) refreshAndCommit(s Source, fn Refresher) error {
	if err := os.MkdirAll(filepath.Join(c.Root, s.Tier), 0o750); err != nil {
		return err
	}

	claim, err := c.claimRefresh(s)
	if err != nil {
		return err
	}
	if !claim.claimed {
		if c.waitForRefreshHook != nil {
			c.waitForRefreshHook(s)
		}
		// Another process is refreshing; wait for it.
		return c.waitForRefresh(s, claim.marker)
	}

	return c.refreshWithClaim(s, fn)
}

// refreshWithClaim assumes the current process already owns the refresh
// marker.
func (c *Cache) refreshWithClaim(s Source, fn Refresher) error {
	// Run slow IO outside any lock.
	refreshCtx := context.Background()
	var cancel context.CancelFunc
	if s.RefreshDeadline > 0 {
		refreshCtx, cancel = context.WithTimeout(refreshCtx, s.RefreshDeadline)

package fizeau

import (
	"context"
	"os"

	"github.com/easel/fizeau/internal/modelcatalog"
	"github.com/easel/fizeau/internal/modelsnapshot"
)

func assembleModelSnapshotFromServiceConfig(ctx context.Context, sc ServiceConfig, cat *modelcatalog.Catalog, cacheRoot string) (modelsnapshot.ModelSnapshot, error) {
	return assembleModelSnapshotFromServiceConfigWithOptions(ctx, sc, cat, cacheRoot, modelsnapshot.AssembleOptions{Refresh: modelsnapshot.RefreshBackground})
}

func assembleModelSnapshotFromServiceConfigWithOptions(ctx context.Context, sc ServiceConfig, cat *modelcatalog.Catalog, cacheRoot string, opts modelsnapshot.AssembleOptions) (modelsnapshot.ModelSnapshot, error) {
	return modelsnapshot.AssembleServiceConfigWithOptions(ctx, serviceConfigToModelSnapshotConfig(sc), cat, cacheRoot, opts)
}

func serviceSnapshotCacheRoot() (string, error) {
	return modelsnapshot.DefaultCacheRoot(os.Getenv, os.UserCacheDir)
}

func serviceConfigToModelSnapshotConfig(sc ServiceConfig) *modelsnapshot.Config {
	if sc == nil {
		return nil
	}
	cfg := &modelsnapshot.Config{
		Default:   sc.DefaultProviderName(),
		Providers: make(map[string]modelsnapshot.ProviderConfig, len(sc.ProviderNames())),
	}
	for _, name := range sc.ProviderNames() {
		entry, ok := sc.Provider(name)
		if !ok {
			continue
		}
		cfg.Providers[name] = modelSnapshotProviderConfig(entry)
	}
	return cfg
}

func modelSnapshotProviderConfig(entry ServiceProviderEntry) modelsnapshot.ProviderConfig {
	out := modelsnapshot.ProviderConfig{
		Type:             entry.Type,
		BaseURL:          entry.BaseURL,
		ServerInstance:   entry.ServerInstance,
		Endpoints:        make([]modelsnapshot.ProviderEndpoint, 0, len(entry.Endpoints)),
		APIKey:           entry.APIKey,
		Headers:          cloneStringMap(entry.Headers),
		Model:            entry.Model,
		Billing:          string(entry.Billing),
		IncludeByDefault: nil,
		ContextWindow:    entry.ContextWindow,
		ConfigError:      entry.ConfigError,
		DailyTokenBudget: entry.DailyTokenBudget,
	}
	if entry.IncludeByDefaultSet {
		v := entry.IncludeByDefault
		out.IncludeByDefault = &v
		out.IncludeByDefaultSet = true
	}
	for _, endpoint := range entry.Endpoints {
		out.Endpoints = append(out.Endpoints, modelsnapshot.ProviderEndpoint{
			Name:           endpoint.Name,
			BaseURL:        endpoint.BaseURL,
			ServerInstance: endpoint.ServerInstance,
		})
	}
	return out
}

func cloneStringMap(src map[string]string) map[string]string {
	if len(src) == 0 {
		return nil
	}
	out := make(map[string]string, len(src))
	for k, v := range src {
		out[k] = v
	}
	return out
}

package discoverycache

import (
	"encoding/json"
	"errors"
	"os"
	"time"
)

// refreshMarker is the tier-2 long-lived marker written when a refresh is
// in progress. Other processes inspect it to decide whether to wait or return
// stale data. JSON payload mirrors ADR-012 §3.
type refreshMarker struct {
	PID       int       `json:"pid"`
	StartedAt time.Time `json:"started_at"`
	Deadline  time.Time `json:"deadline"`
	LastError string    `json:"last_error,omitempty"`
}

// readMarker reads the .refreshing file for s. Returns (nil, nil) if absent.
func readMarker(path string) (*refreshMarker, error) {
	data, err := os.ReadFile(path) // #nosec G304
	if errors.Is(err, os.ErrNotExist) {
		return nil, nil
	}
	if err != nil {
		return nil, err
	}
	var m refreshMarker
	if err := json.Unmarshal(data, &m); err != nil {
		// Corrupt marker — treat as absent so the caller can reclaim.
		return nil, nil
	}
	return &m, nil
}

// writeMarker writes m to path, overwriting any existing file.
func writeMarker(path string, m *refreshMarker) error {
	data, err := json.Marshal(m)
	if err != nil {
		return err
	}
	// Overwrite (not O_EXCL) because claimRefresh already holds the tier-1 lock.
	f, err := os.OpenFile(path, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0o600) // #nosec G304
	if err != nil {
		return err
	}
	if _, werr := f.Write(data); werr != nil {
		_ = f.Close()
		_ = os.Remove(path)
		return werr
	}
	return f.Close()
}

// isStale returns true when m should be treated as an orphan.
// A marker is stale when: the owner PID is dead, OR now > deadline + 2×RefreshDeadline.
// The deadline-based check is the safety net for PID reuse (ADR-012 §3, §10 test).
func isStale(s Source, m *refreshMarker) bool {
	if m == nil {
		return true
	}
	if !processAlive(m.PID) {
		return true
	}
	// 2× multiplier per ADR-012 "Marker staleness threshold = 2 × refresh deadline"
	threshold := s.RefreshDeadline * stalenessMultiplier
	return time.Now().After(m.Deadline.Add(threshold))
}

// isMarkerActiveForPrune is a conservative check used only by Prune when the
// source's RefreshDeadline is unknown. A marker is active if its PID is alive
// and the deadline itself has not passed (no multiplier).
func isMarkerActiveForPrune(m *refreshMarker) bool {
	if m == nil {
		return false
	}
	return processAlive(m.PID) && time.Now().Before(m.Deadline)
}

