// Gemini CLI's /model manage TUI surfaces per-tier usage as rows such as:
//
//	Flash                  4% used      Resets 9:13 PM (23h 46m)
//	Flash Lite             0% used      Resets 9:27 PM (24h)
//	Pro                    100% used
//
// Names are version-sensitive; parse_gemini_model_manage accepts a small set
// of known tier labels and tolerates surrounding decoration (box-drawing
// glyphs, leading bullets, status badges).

var geminiAnsiPattern = regexp.MustCompile(`\x1b(?:\[[0-9;?]*[a-zA-Z]|[^[])`)

func stripGeminiANSI(s string) string {
	return geminiAnsiPattern.ReplaceAllString(s, "")
}

var (
	geminiUsedPercentPattern = regexp.MustCompile(`(\d+(?:\.\d+)?)\s*%\s*used`)
	geminiResetPattern       = regexp.MustCompile(`(?i)reset[s]?\s+(.*)`)
)

// geminiTier represents a tier surfaced in the /model manage dialog.
type geminiTier struct {
	// Label is the tier label expected in the Gemini CLI UI (case-insensitive).
	Label string
	// LimitID is the stable identifier persisted into cassettes and caches.
	// Downstream consumers compare LimitIDs, not labels.
	LimitID string
	// DefaultModel is the concrete model ID mapped to this tier.
	DefaultModel string
}

var geminiTiers = []geminiTier{
	{Label: "Pro", LimitID: "gemini-pro", DefaultModel: "gemini-2.5-pro"},
	{Label: "Flash Lite", LimitID: "gemini-flash-lite", DefaultModel: "gemini-2.5-flash-lite"},
	{Label: "Flash", LimitID: "gemini-flash", DefaultModel: "gemini-2.5-flash"},
}

// ParseGeminiModelManage parses the raw text captured from `gemini` in
// /model manage. It returns one QuotaWindow per recognised tier, with the
// tier label, used percent, reset text, and a derived quota state. Tiers
// missing in the captured text are simply absent from the returned slice.
func ParseGeminiModelManage(text string) []harnesses.QuotaWindow {
	text = stripGeminiANSI(strings.ReplaceAll(text, "\r\n", "\n"))
	lines := strings.Split(text, "\n")

	windows := make([]harnesses.QuotaWindow, 0, len(geminiTiers))
	seen := map[string]bool{}

	for i := 0; i < len(lines); i++ {
		line := lines[i]
		tier := tierForLine(line)
		if tier == nil {
			continue
		}
		if seen[tier.LimitID] {
			continue
		}
		// Look at the current line and up to two following lines for the
		// "% used" token and (optionally) a "Resets ..." fragment.
		usedPct, hasUsed, resetText := harvestTierEvidence(lines, i)
		if !hasUsed {
			continue
		}
		seen[tier.LimitID] = true
		windows = append(windows, harnesses.QuotaWindow{
			Name:        tier.Label,
			LimitID:     tier.LimitID,
			UsedPercent: usedPct,
			ResetsAt:    resetText,
			State:       geminiQuotaState(usedPct),
		})
	}
	return windows
}

func tierForLine(line string) *geminiTier {
	lower := strings.ToLower(line)
	// Match longer labels first so "Flash Lite" is never matched as "Flash".
	for i := range geminiTiers {
		if containsTierLabel(lower, strings.ToLower(geminiTiers[i].Label)) {
			return &geminiTiers[i]
		}
	}
	return nil
}

// containsTierLabel checks that the lowercase tier label appears in the line
// with word-like boundaries so "flashback" never matches "flash".
func containsTierLabel(lowerLine, lowerLabel string) bool {
	idx := strings.Index(lowerLine, lowerLabel)
	if idx < 0 {
		return false
	}
	if idx > 0 {
		prev := lowerLine[idx-1]
		if isTierLabelRune(prev) {
			return false
		}
	}
	end := idx + len(lowerLabel)
	if end < len(lowerLine) {
		next := lowerLine[end]
		if isTierLabelRune(next) {
			return false
		}
	}
	return true
}

func isTierLabelRune(b byte) bool {
	return (b >= 'a' && b <= 'z') || (b >= '0' && b <= '9')
}

func harvestTierEvidence(lines []string, start int) (float64, bool, string) {
	var usedPct float64
	var hasUsed bool
	var resetText string
	end := start + 3
	if end > len(lines) {
		end = len(lines)
	}
	for j := start; j < end; j++ {
		frag := lines[j]
		if !hasUsed {
			if m := geminiUsedPercentPattern.FindStringSubmatch(frag); m != nil {
				if pct, err := strconv.ParseFloat(m[1], 64); err == nil {
					usedPct = pct
					hasUsed = true
				}
			}
		}
		if resetText == "" {
			if m := geminiResetPattern.FindStringSubmatch(frag); m != nil {
				resetText = strings.TrimSpace(m[1])
			}
		}
		if hasUsed && resetText != "" {
			break
		}
	}
	return usedPct, hasUsed, resetText
}

// geminiQuotaState mirrors harnesses.QuotaStateFromUsedPercent but treats
// exhausted tiers (>=100% used) as an explicit "exhausted" state so downstream
// routing can distinguish a fully blown tier from merely approaching the cap.
func geminiQuotaState(used float64) string {
	rounded := int(math.Ceil(used))
	if rounded >= 100 {
		return "exhausted"
	}
	if rounded >= 95 {
		return "blocked"
	}
	return "ok"
}

// FindGeminiQuotaWindow returns the QuotaWindow matching limitID, or nil.
func FindGeminiQuotaWindow(windows []harnesses.QuotaWindow, limitID string) *harnesses.QuotaWindow {
	for i := range windows {
		if windows[i].LimitID == limitID {
			return &windows[i]
		}
	}
	return nil
}

// TierLimitIDForModel returns the tier limit_id that covers the given concrete
// Gemini model ID (e.g. "gemini-2.5-pro" -> "gemini-pro"). Unknown models
// return ("", false).
func TierLimitIDForModel(model string) (string, bool) {
	normalized := strings.ToLower(strings.TrimSpace(model))
	if normalized == "" {
		return "", false
	}
	// Match the more specific label first (flash-lite before flash).
	if strings.Contains(normalized, "flash-lite") || strings.Contains(normalized, "flash lite") {
		return "gemini-flash-lite", true
	}
	if strings.Contains(normalized, "pro") {
		return "gemini-pro", true
	}
	if strings.Contains(normalized, "flash") {
		return "gemini-flash", true
	}
	return "", false
}

package gemini

import (
	"encoding/json"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/safefs"
)

const geminiAuthFreshnessWindow = 7 * 24 * time.Hour

const (
	authTypeGeminiAPIKey = "gemini-api-key"
	authTypeOAuth        = "oauth-personal"
	authTypeVertexAI     = "vertex-ai"
	authTypeComputeADC   = "compute-default-credentials"
	authTypeGateway      = "gateway"
)

// authSnapshot captures non-secret Gemini CLI auth/account evidence. It never
// stores API keys, OAuth tokens, refresh tokens, or raw credential payloads.
type authSnapshot struct {
	Authenticated bool
	AuthType      string
	Account       *harnesses.AccountInfo
	CapturedAt    time.Time
	Fresh         bool
	Source        string
	Detail        string
}

// readAuthEvidence reads Gemini CLI auth evidence from the user's configured
// environment and ~/.gemini directory. It is best-effort because Gemini CLI has
// no stable non-interactive quota command; routing uses this as auth/account
// freshness evidence and exposes quota as unknown.
func readAuthEvidence(now time.Time) authSnapshot {
	if now.IsZero() {
		now = time.Now()
	}
	if authType := authTypeFromEnv(); authType != "" {
		return authSnapshot{
			Authenticated: true,
			AuthType:      authType,
			Account:       accountForAuthType(authType),
			CapturedAt:    now.UTC(),
			Fresh:         true,
			Source:        "environment",
			Detail:        "Gemini auth selected from environment; secret values are not read",
		}
	}
	home, err := os.UserHomeDir()
	if err != nil || home == "" {
		return authSnapshot{Source: "~/.gemini", Detail: "home directory unavailable"}
	}
	return readAuthEvidenceFromDir(filepath.Join(home, ".gemini"), now)
}

// readAuthEvidenceFromDir reads non-secret Gemini CLI auth evidence from a
// caller-provided .gemini directory. Tests use this for credential-free replay.
func readAuthEvidenceFromDir(dir string, now time.Time) authSnapshot {
	if now.IsZero() {
		now = time.Now()
	}
	settingsPath := filepath.Join(dir, "settings.json")
	authType, settingsTime, settingsOK := readSelectedAuthType(settingsPath)
	if authType == "" {
		return authSnapshot{
			Source:     settingsPath,
			CapturedAt: settingsTime,
			Fresh:      settingsOK && isFresh(settingsTime, now),
			Detail:     "Gemini CLI auth method not configured",
		}
	}

	switch authType {
	case authTypeOAuth:
		return readOAuthEvidence(dir, authType, settingsTime, now)
	case authTypeGeminiAPIKey, authTypeVertexAI, authTypeGateway, authTypeComputeADC:
		return authSnapshot{
			Authenticated: true,
			AuthType:      authType,
			Account:       accountForAuthType(authType),
			CapturedAt:    settingsTime,
			Fresh:         isFresh(settingsTime, now),
			Source:        settingsPath,
			Detail:        "Gemini CLI auth method configured; secret material is external to DDx",
		}
	default:
		return authSnapshot{
			AuthType:   authType,
			Source:     settingsPath,
			CapturedAt: settingsTime,
			Fresh:      isFresh(settingsTime, now),
			Detail:     "Gemini CLI auth method is not recognized by DDx",
		}
	}
}

func readSelectedAuthType(path string) (string, time.Time, bool) {
	st, err := os.Stat(path)
	if err != nil || st.IsDir() {
		return "", time.Time{}, false
	}
	data, err := safefs.ReadFile(path)
	if err != nil {
		return "", st.ModTime().UTC(), false
	}
	var settings struct {
		Security struct {
			Auth struct {
				SelectedType string `json:"selectedType"`
			} `json:"auth"`
		} `json:"security"`
	}
	if err := json.Unmarshal(data, &settings); err != nil {
		return "", st.ModTime().UTC(), false
	}
	return strings.TrimSpace(settings.Security.Auth.SelectedType), st.ModTime().UTC(), true
}

func readOAuthEvidence(dir, authType string, settingsTime, now time.Time) authSnapshot {
	oauthPath := filepath.Join(dir, "oauth_creds.json")
	st, err := os.Stat(oauthPath)
	if err != nil || st.IsDir() {
		return authSnapshot{
			AuthType:   authType,
			Source:     oauthPath,
			CapturedAt: settingsTime,
			Fresh:      isFresh(settingsTime, now),
			Detail:     "Gemini OAuth credentials are missing",
		}
	}
	data, err := safefs.ReadFile(oauthPath)
	if err != nil {
		return authSnapshot{
			AuthType:   authType,
			Source:     oauthPath,
			CapturedAt: st.ModTime().UTC(),
			Fresh:      isFresh(st.ModTime(), now),
			Detail:     "Gemini OAuth credentials could not be read",
		}
	}
	var creds struct {
		AccessToken  string `json:"access_token"`
		RefreshToken string `json:"refresh_token"`
		ExpiryDate   int64  `json:"expiry_date"`
	}
	if err := json.Unmarshal(data, &creds); err != nil {
		return authSnapshot{
			AuthType:   authType,
			Source:     oauthPath,
			CapturedAt: st.ModTime().UTC(),
			Fresh:      isFresh(st.ModTime(), now),
			Detail:     "Gemini OAuth credentials are malformed",
		}
	}
	authenticated := creds.RefreshToken != "" || creds.AccessToken != ""
	if creds.ExpiryDate > 0 && creds.RefreshToken == "" {
		expires := time.UnixMilli(creds.ExpiryDate)
		authenticated = authenticated && expires.After(now)
	}
	capturedAt := maxTime(settingsTime, st.ModTime().UTC())
	return authSnapshot{
		Authenticated: authenticated,
		AuthType:      authType,
		Account:       readGoogleAccount(dir),
		CapturedAt:    capturedAt,
		Fresh:         isFresh(capturedAt, now),
		Source:        oauthPath,
		Detail:        oauthDetail(authenticated),
	}
}

func readGoogleAccount(dir string) *harnesses.AccountInfo {
	data, err := safefs.ReadFile(filepath.Join(dir, "google_accounts.json"))
	if err != nil {
		return &harnesses.AccountInfo{PlanType: "Gemini OAuth"}
	}
	var accounts struct {
		Active string `json:"active"`
	}
	if err := json.Unmarshal(data, &accounts); err != nil {
		return &harnesses.AccountInfo{PlanType: "Gemini OAuth"}
	}
	account := &harnesses.AccountInfo{PlanType: "Gemini OAuth"}
	if strings.Contains(accounts.Active, "@") {
		account.Email = accounts.Active
	}
	return account
}

func accountForAuthType(authType string) *harnesses.AccountInfo {
	switch authType {
	case authTypeGeminiAPIKey:
		return &harnesses.AccountInfo{PlanType: "Gemini API key"}
	case authTypeVertexAI:
		return &harnesses.AccountInfo{PlanType: "Vertex AI"}
	case authTypeComputeADC:
		return &harnesses.AccountInfo{PlanType: "Google ADC"}
	case authTypeGateway:
		return &harnesses.AccountInfo{PlanType: "Gemini gateway"}
	default:
		return &harnesses.AccountInfo{PlanType: authType}
	}
}

func authTypeFromEnv() string {
	if os.Getenv("GOOGLE_GENAI_USE_GCA") != "" {
		return authTypeGateway
	}
	if os.Getenv("GOOGLE_GENAI_USE_VERTEXAI") != "" {
		return authTypeVertexAI
	}
	if os.Getenv("GOOGLE_API_KEY") != "" || os.Getenv("GEMINI_API_KEY") != "" {
		return authTypeGeminiAPIKey
	}

package gemini

import (
	"os"
	"path/filepath"
	"runtime"
	"testing"
	"time"

	"github.com/easel/fizeau/internal/pty/cassette"
)

func TestReadGeminiQuotaViaPTY_CapturesTierUsage(t *testing.T) {
	if runtime.GOOS == "windows" {
		t.Skip("shell-backed PTY probes require Unix PTY support")
	}
	dir := t.TempDir()
	script := filepath.Join(dir, "fake-gemini")
	// Emits a ready prompt, reads the slash-command, then prints a
	// fixture resembling Gemini CLI 0.38.2 /model manage output one tier
	// at a time. The sleeps force the probe to tolerate incremental PTY
	// rendering instead of assuming the first parsed row is the final
	// screen. The final sleep keeps the script alive long enough for the
	// probe to harvest the screen before we send SIGTERM via the probe's
	// stop path.
	body := `#!/bin/sh
printf 'Gemini CLI 0.38.2\r\n> '
IFS= read line
printf 'Model management\r\n\r\n'
printf '  Flash         4%% used      Resets 9:13 PM (23h 46m)\r\n'
sleep 0.1
printf '  Flash Lite    0%% used      Resets 9:27 PM (24h)\r\n'
sleep 0.1
printf '  Pro         100%% used\r\n\r\n'
sleep 2
`
	if err := os.WriteFile(script, []byte(body), 0o700); err != nil {
		t.Fatalf("write script: %v", err)
	}
	cassetteDir := filepath.Join(dir, "cassette")

	windows, err := ReadGeminiQuotaViaPTY(3*time.Second, WithQuotaPTYCommand(script), WithQuotaPTYCassetteDir(cassetteDir))
	if err != nil {
		t.Fatalf("ReadGeminiQuotaViaPTY: %v", err)
	}
	if len(windows) != 3 {
		t.Fatalf("want 3 tier windows, got %d: %#v", len(windows), windows)
	}
	flash := FindGeminiQuotaWindow(windows, "gemini-flash")
	if flash == nil || flash.UsedPercent != 4 {
		t.Fatalf("flash parsed from PTY: %#v", flash)
	}
	lite := FindGeminiQuotaWindow(windows, "gemini-flash-lite")
	if lite == nil || lite.UsedPercent != 0 {
		t.Fatalf("flash-lite parsed from PTY: %#v", lite)
	}
	pro := FindGeminiQuotaWindow(windows, "gemini-pro")
	if pro == nil || pro.UsedPercent != 100 || pro.State != "exhausted" {
		t.Fatalf("pro parsed from PTY: %#v", pro)
	}

	reader, err := cassette.Open(cassetteDir)
	if err != nil {
		t.Fatalf("cassette.Open: %v", err)
	}
	quota := reader.Quota()
	if quota.Source != "pty" {
		t.Fatalf("cassette quota source: %q", quota.Source)
	}
	if quota.CapturedAt == "" {
		t.Fatal("cassette quota must record captured_at")
	}
	if quota.FreshnessWindow != defaultGeminiQuotaStaleAfter.String() {
		t.Fatalf("cassette freshness window: %q", quota.FreshnessWindow)
	}
	if len(quota.Windows) != 3 {
		t.Fatalf("cassette windows: %d", len(quota.Windows))
	}
}

func TestReadGeminiQuotaFromCassette_RoundTrip(t *testing.T) {
	if runtime.GOOS == "windows" {
		t.Skip("shell-backed PTY probes require Unix PTY support")
	}
	dir := t.TempDir()
	script := filepath.Join(dir, "fake-gemini")
	body := `#!/bin/sh
printf '> '
IFS= read line
cat <<'EOF'
  Flash    4% used      Resets 9:13 PM
  Pro    100% used
EOF
sleep 2
`
	if err := os.WriteFile(script, []byte(body), 0o700); err != nil {
		t.Fatalf("write: %v", err)
	}
	cassetteDir := filepath.Join(dir, "cassette")
	if _, err := ReadGeminiQuotaViaPTY(3*time.Second, WithQuotaPTYCommand(script), WithQuotaPTYCassetteDir(cassetteDir)); err != nil {
		t.Fatalf("ReadGeminiQuotaViaPTY: %v", err)
	}
	windows, err := ReadGeminiQuotaFromCassette(cassetteDir)
	if err != nil {
		t.Fatalf("ReadGeminiQuotaFromCassette: %v", err)
	}
	if len(windows) != 2 {
		t.Fatalf("cassette replay lost a tier: %#v", windows)
	}
}

package config

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/triage"
	"gopkg.in/yaml.v3"
)

// RoutingMigrationError signals that the loaded config carries a removed
// agent.routing field. The field is gone for good; configs must be migrated
// before DDx will load them.
type RoutingMigrationError struct {
	Field string
	Path  string
}

func (e *RoutingMigrationError) Error() string {
	return fmt.Sprintf(
		"%s: %s has been removed. "+
			"Migration: delete the field from your .ddx/config.yaml. "+
			"See docs/migrations/routing-config.md.",
		e.Path, e.Field)
}

// checkRoutingMigration parses the raw config bytes and hard-errors on any
// removed agent.routing fields.
func checkRoutingMigration(path string, data []byte) error {
	var raw map[string]any
	if err := yaml.Unmarshal(data, &raw); err != nil {
		return nil // YAML errors surface from the validator below
	}
	agent, _ := raw["agent"].(map[string]any)
	if agent == nil {
		return nil
	}
	routing, _ := agent["routing"].(map[string]any)
	if routing == nil {
		return nil
	}
	// routinglint:legacy-rejection reason="hard-error rejection of retired routing keys per ddx-3bd7396a"
	for _, field := range []string{"default_harness", "profile_ladders", "model_overrides"} {
		if _, ok := routing[field]; ok {
			return &RoutingMigrationError{
				Field: "agent.routing." + field,
				Path:  path,
			}
		}
	}
	return nil
}

// Type aliases for smooth transition
type Config = NewConfig
type Repository = RepositoryConfig

// ConfigError represents a single configuration error
type ConfigError struct {
	Field      string
	Value      string
	Message    string
	Suggestion string
}

func (e *ConfigError) Error() string {
	return fmt.Sprintf("%s: %s", e.Field, e.Message)
}

// ValidationError represents multiple configuration errors
type ValidationError struct {
	Errors []*ConfigError
}

func (e *ValidationError) Error() string {
	if len(e.Errors) == 1 {
		return e.Errors[0].Error()
	}
	return fmt.Sprintf("%d configuration errors found", len(e.Errors))
}

// Load loads configuration using the new simplified approach
func Load() (*Config, error) {
	workingDir, err := os.Getwd()
	if err != nil {
		return nil, fmt.Errorf("failed to get working directory: %w", err)
	}
	return LoadWithWorkingDir(workingDir)
}

// LoadWithWorkingDir loads configuration from a specific working directory
func LoadWithWorkingDir(workingDir string) (*Config, error) {
	if workingDir == "" {
		var err error
		workingDir, err = os.Getwd()
		if err != nil {
			return nil, fmt.Errorf("failed to get working directory: %w", err)
		}
	}

	// Use the new ConfigLoader to load from .ddx/config.yaml only
	loader, err := NewConfigLoaderWithWorkingDir(workingDir)
	if err != nil {
		return nil, fmt.Errorf("failed to create config loader: %w", err)
	}

	// Pre-validation migration check: surface a friendly hard error for
	// removed agent.routing fields before the schema validator sees the file.
	// This happens before LoadConfig so the migration message is what the
	// operator sees.
	configPath := projectStatePath(workingDir, "config.yaml")
	if data, readErr := os.ReadFile(configPath); readErr == nil {
		if migErr := checkRoutingMigration(configPath, data); migErr != nil {
			return nil, migErr
		}
	}

	config, err := loader.LoadConfig()
	if err != nil {
		// If no config file exists, return default config
		if os.IsNotExist(err) || strings.Contains(err.Error(), "no configuration file found") {
			config = DefaultNewConfig()
		} else {
			return nil, err
		}
	}

	// Apply defaults to ensure complete configuration
	config.ApplyDefaults()
	if config.Agent != nil && config.Agent.Routing != nil &&
		len(config.Agent.Routing.ProfilePriority) > 0 {
		fmt.Fprintln(os.Stderr, "warning: agent.routing.profile_priority is deprecated and will be removed in a future version")
	}
	if err := mergeGlobalExecutionConfig(config, workingDir); err != nil {
		return nil, err
	}

	// Override library path with environment variable if set
	if envLibraryPath := os.Getenv("DDX_LIBRARY_BASE_PATH"); envLibraryPath != "" {
		config.Library.Path = envLibraryPath
	}

	// Validate the final configuration
	if err := config.Validate(); err != nil {
		return nil, fmt.Errorf("configuration validation failed: %w", err)
	}

	return config, nil
}

func mergeGlobalExecutionConfig(projectCfg *Config, workingDir string) error {
	if projectCfg == nil {
		return nil
	}
	home, err := os.UserHomeDir()
	if err != nil {
		return nil
	}
	globalPath := ddxroot.JoinHome(home, "config.yaml")
	projectPath := projectStatePath(workingDir, "config.yaml")
	if filepath.Clean(globalPath) == filepath.Clean(projectPath) {
		return nil
	}
	if _, err := os.Stat(globalPath); err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return fmt.Errorf("stat global configuration %s: %w", globalPath, err)
	}
	loader, err := NewConfigLoaderWithWorkingDir(filepath.Dir(globalPath))
	if err != nil {
		return fmt.Errorf("failed to create global config loader: %w", err)
	}
	globalCfg, err := loader.LoadConfigFromPath(globalPath)
	if err != nil {
		return fmt.Errorf("failed to load global configuration from %s: %w", globalPath, err)
	}
	mergeExecutionsConfig(projectCfg, globalCfg)
	return nil
}

func mergeExecutionsConfig(projectCfg, globalCfg *Config) {
	if projectCfg == nil || globalCfg == nil || globalCfg.Executions == nil {
		return
	}
	if projectCfg.Executions == nil {
		cp := *globalCfg.Executions
		cp.Docker = globalCfg.Executions.Docker.Clone()
		projectCfg.Executions = &cp
		return
	}
	if projectCfg.Executions.AttemptBackend == "" {
		projectCfg.Executions.AttemptBackend = globalCfg.Executions.AttemptBackend
	}
	if projectCfg.Executions.TempWorktreeRoot == "" {
		projectCfg.Executions.TempWorktreeRoot = globalCfg.Executions.TempWorktreeRoot
	}
	if projectCfg.Executions.Docker == nil {
		projectCfg.Executions.Docker = globalCfg.Executions.Docker.Clone()
		return
	}
	mergeDockerConfig(projectCfg.Executions.Docker, globalCfg.Executions.Docker)
}

func mergeDockerConfig(projectDocker, globalDocker *ExecutionsDockerConfig) {
	if projectDocker == nil || globalDocker == nil {
		return
	}
	if projectDocker.Image == "" {
		projectDocker.Image = globalDocker.Image
	}
	if projectDocker.ProjectImage == "" {
		projectDocker.ProjectImage = globalDocker.ProjectImage
	}
	if projectDocker.ProjectDockerfile == "" {
		projectDocker.ProjectDockerfile = globalDocker.ProjectDockerfile
	}

package config

import (
	"fmt"
	"os"
	"path/filepath"
	"sync"

	"gopkg.in/yaml.v3"
)

var configReachabilityOnce sync.Once

func anchorConfigReachability() {
	configReachabilityOnce.Do(func() {
		_, _ = NewConfigLoader()

		tmpDir, err := MkdirExecutionScratch("", "ddx-config-anchor-*")
		if err == nil {
			defer func() {
				_ = os.RemoveAll(tmpDir)
			}()

			_, _ = NewConfigLoaderWithWorkingDir(tmpDir)
			loader := &ConfigLoader{workingDir: tmpDir}
			_, _, _ = loader.DetectConfigFormat()
			_, _ = ResolveLibraryResource("anchor.md", "", tmpDir)
		}

		_ = NewTestConfigForLoop(TestLoopConfigOpts{})
		_ = NewTestConfigForRun(TestRunConfigOpts{})
		_ = NewTestConfigForBead(TestBeadConfigOpts{})
		_ = TestBeadOverrides(TestBeadConfigOpts{})
		_ = TestLoopOverrides(TestLoopConfigOpts{})
	})
}

// ConfigLoader handles loading configuration files with validation
type ConfigLoader struct {
	validator  Validator
	workingDir string
}

// NewConfigLoader creates a new configuration loader with validation
func NewConfigLoader() (*ConfigLoader, error) {
	workingDir, err := os.Getwd()
	if err != nil {
		return nil, fmt.Errorf("failed to get working directory: %w", err)
	}
	return NewConfigLoaderWithWorkingDir(workingDir)
}

// NewConfigLoaderWithWorkingDir creates a new configuration loader with a specific working directory
func NewConfigLoaderWithWorkingDir(workingDir string) (*ConfigLoader, error) {
	validator, err := NewValidator()
	if err != nil {
		return nil, fmt.Errorf("failed to create validator: %w", err)
	}

	return &ConfigLoader{
		validator:  validator,
		workingDir: workingDir,
	}, nil
}

// LoadConfig loads configuration from .ddx/config.yaml only
func (cl *ConfigLoader) LoadConfig() (*NewConfig, error) {
	configPath := projectStatePath(cl.workingDir, "config.yaml")
	if _, err := os.Stat(configPath); err != nil {
		return nil, fmt.Errorf("no configuration file found at %s", configPath)
	}

	return cl.loadNewFormat(configPath)
}

// LoadConfigFromPath loads configuration from a specific path (new format only)
func (cl *ConfigLoader) LoadConfigFromPath(path string) (*NewConfig, error) {
	// Convert relative path to absolute based on working directory
	if !filepath.IsAbs(path) {
		path = filepath.Join(cl.workingDir, path)
	}

	return cl.loadNewFormat(path)
}

// loadNewFormat loads and validates the new configuration format
func (cl *ConfigLoader) loadNewFormat(path string) (*NewConfig, error) {
	// Read file
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("failed to read config file %s: %w", path, err)
	}

	// Validate using two-phase validation
	if err := cl.validator.Validate(data); err != nil {
		return nil, fmt.Errorf("configuration validation failed: %w", err)
	}

	// Parse YAML into new config structure
	var config NewConfig
	if err := yaml.Unmarshal(data, &config); err != nil {
		return nil, fmt.Errorf("failed to parse config YAML from %s: %w", path, err)
	}

	// Apply defaults to missing fields
	config.ApplyDefaults()

	return &config, nil
}

// SaveConfig saves configuration in the new format
func (cl *ConfigLoader) SaveConfig(config *NewConfig, path string) error {
	// Convert relative path to absolute based on working directory
	if !filepath.IsAbs(path) {
		path = filepath.Join(cl.workingDir, path)
	}

	// Create directory if it doesn't exist
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0755); err != nil {
		return fmt.Errorf("failed to create config directory %s: %w", dir, err)
	}

	// Marshal to YAML
	data, err := yaml.Marshal(config)
	if err != nil {
		return fmt.Errorf("failed to marshal config: %w", err)
	}

	// Validate before saving
	if err := cl.validator.Validate(data); err != nil {
		return fmt.Errorf("config validation failed before save: %w", err)
	}

	// Write file with secure permissions
	if err := os.WriteFile(path, data, 0644); err != nil {
		return fmt.Errorf("failed to write config file %s: %w", path, err)
	}

	return nil
}

// DetectConfigFormat determines if .ddx/config.yaml exists in working directory
func (cl *ConfigLoader) DetectConfigFormat() (string, string, error) {
	configPath := projectStatePath(cl.workingDir, "config.yaml")
	if _, err := os.Stat(configPath); err == nil {
		return "new", configPath, nil
	}

	return "none", "", fmt.Errorf("no configuration file found at %s", configPath)
}

package gemini

import (
	"context"
	"fmt"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/harnesses/ptyquota"
	"github.com/easel/fizeau/internal/pty/cassette"
	"github.com/easel/fizeau/internal/pty/session"
)

const geminiQuotaSettleTime = 150 * time.Millisecond

type quotaPTYOptions struct {
	binary      string
	args        []string
	workdir     string
	env         []string
	cassetteDir string
}

// QuotaPTYOption configures a Gemini quota PTY probe.
type QuotaPTYOption func(*quotaPTYOptions)

func WithQuotaPTYCommand(binary string, args ...string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.binary = binary
		opts.args = append([]string(nil), args...)
	}
}

func WithQuotaPTYWorkdir(workdir string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.workdir = workdir
	}
}

func WithQuotaPTYEnv(env ...string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.env = append([]string(nil), env...)
	}
}

func WithQuotaPTYCassetteDir(dir string) QuotaPTYOption {
	return func(opts *quotaPTYOptions) {
		opts.cassetteDir = dir
	}
}

// ReadGeminiQuotaViaPTY launches Gemini, sends /model manage, and returns the
// parsed tier quota windows. Callers must only treat non-empty, non-error
// results as authoritative — Gemini CLI renders /model manage as a version-
// sensitive TUI, so a timeout or empty parse means "quota unknown".
func ReadGeminiQuotaViaPTY(timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, error) {
	windows, _, err := captureGeminiQuotaViaPTY(context.Background(), timeout, opts...)
	return windows, err
}

// ReadGeminiQuotaFromCassette replays a previously recorded cassette and
// re-parses its final frame as Gemini /model manage output.
func ReadGeminiQuotaFromCassette(dir string) ([]harnesses.QuotaWindow, error) {
	reader, err := cassette.Open(dir)
	if err != nil {
		return nil, err
	}
	text := reader.Final().FinalText
	if text == "" {
		frames := reader.Frames()
		if len(frames) > 0 {
			text = stringsJoinLines(frames[len(frames)-1].Text)
		}
	}
	windows := ParseGeminiModelManage(text)
	if len(windows) == 0 {
		return nil, fmt.Errorf("no gemini tier quota windows found in cassette")
	}
	return windows, nil
}

func captureGeminiQuotaViaPTY(ctx context.Context, timeout time.Duration, opts ...QuotaPTYOption) ([]harnesses.QuotaWindow, ptyquota.Result, error) {
	cfg := quotaPTYOptions{binary: "gemini"}
	for _, opt := range opts {
		if opt != nil {
			opt(&cfg)
		}
	}
	var windows []harnesses.QuotaWindow
	result, err := ptyquota.Run(ctx, ptyquota.Config{
		HarnessName:  "gemini",
		Binary:       cfg.binary,
		Args:         cfg.args,
		Workdir:      cfg.workdir,
		Env:          cfg.env,
		Command:      "/model manage\r",
		ReadyMarkers: []string{">", "❯"},
		DoneWhen:     geminiQuotaComplete(geminiQuotaSettleTime),
		Timeout:      timeout,
		Size:         session.Size{Rows: 50, Cols: 220},
		CassetteDir:  cfg.cassetteDir,
		Quota: func(text string) (cassette.QuotaRecord, error) {
			windows = ParseGeminiModelManage(text)
			if len(windows) == 0 {
				return cassette.QuotaRecord{}, fmt.Errorf("no gemini tier quota windows found in /model manage output")
			}
			return geminiQuotaRecord(windows), nil
		},
	})
	if err != nil {
		return nil, result, err
	}
	if len(windows) == 0 {
		windows = ParseGeminiModelManage(result.Text)
	}
	if len(windows) == 0 {
		return nil, result, fmt.Errorf("no gemini tier quota windows found in /model manage output")
	}
	return windows, result, nil
}

// geminiQuotaComplete returns a DoneWhen predicate that waits for the parsed
// tier set to stop changing. Gemini CLI renders /model manage incrementally, so
// the first parsed row is not enough evidence that the dialog has settled.
func geminiQuotaComplete(stableFor time.Duration) func(string) bool {
	var lastSignature string
	var lastChange time.Time
	return func(text string) bool {
		windows := ParseGeminiModelManage(text)
		if len(windows) == 0 {
			lastSignature = ""
			lastChange = time.Time{}
			return false
		}
		if stableFor <= 0 {
			return true
		}
		signature := geminiQuotaSignature(windows)
		now := time.Now()
		if signature != lastSignature {
			lastSignature = signature
			lastChange = now
			return false
		}
		if lastChange.IsZero() {
			lastChange = now
			return false
		}
		return now.Sub(lastChange) >= stableFor
	}
}

func geminiQuotaSignature(windows []harnesses.QuotaWindow) string {
	var b strings.Builder
	for _, window := range windows {
		fmt.Fprintf(&b, "%s|%s|%g|%s|%s\n", window.LimitID, window.Name, window.UsedPercent, window.ResetsAt, window.State)
	}
	return b.String()
}

func geminiQuotaRecord(windows []harnesses.QuotaWindow) cassette.QuotaRecord {
	records := make([]map[string]any, 0, len(windows))
	for _, window := range windows {
		records = append(records, map[string]any{
			"name":         window.Name,
			"limit_id":     window.LimitID,
			"used_percent": window.UsedPercent,
			"resets_at":    window.ResetsAt,
			"state":        window.State,
		})
	}
	return cassette.QuotaRecord{
		Source:            "pty",
		Status:            string(ptyquota.StatusOK),
		CapturedAt:        time.Now().UTC().Format(time.RFC3339),
		FreshnessWindow:   defaultGeminiQuotaStaleAfter.String(),
		StalenessBehavior: "stale gemini quota evidence keeps Gemini out of automatic routing and is treated as limited",
		Windows:           records,
	}
}

func stringsJoinLines(lines []string) string {
	out := ""
	for i, line := range lines {
		if i > 0 {
			out += "\n"
		}
		out += line
	}
	return out
}

package ptyquota

import (
	"bytes"
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"runtime"
	"strings"
	"sync"
	"time"

	"github.com/easel/fizeau/internal/pty/cassette"
	"github.com/easel/fizeau/internal/pty/session"
	"github.com/easel/fizeau/internal/pty/terminal"
	"github.com/easel/fizeau/internal/safefs"
)

type Status string

const (
	StatusOK              Status = "ok"
	StatusUnavailable     Status = "unavailable"
	StatusUnauthenticated Status = "unauthenticated"
	StatusError           Status = "error"
)

type ProbeError struct {
	Status Status
	Reason string
	Err    error
}

func (e *ProbeError) Error() string {
	if e == nil {
		return ""
	}
	reason := e.Reason
	if reason == "" {
		reason = string(e.Status)
	}
	if e.Err == nil {
		return reason
	}
	return reason + ": " + e.Err.Error()
}

func (e *ProbeError) Unwrap() error {
	if e == nil {
		return nil
	}
	return e.Err
}

func ErrorStatus(err error) Status {
	if err == nil {
		return StatusOK
	}
	var probeErr *ProbeError
	if errors.As(err, &probeErr) {
		return probeErr.Status
	}
	return StatusError
}

type Config struct {
	HarnessName string
	Binary      string
	// BinaryVersion is stamped into accepted cassette manifests. When empty,
	// Run makes a best-effort short --version probe and records "unknown" if
	// the harness does not answer quickly.
	BinaryVersion string
	Args          []string
	Workdir       string
	Env           []string

	Command            string
	ReadyMarkers       []string
	DoneMarkers        []string
	DoneAnyMarkers     []string
	DoneWhen           func(string) bool
	ResetBeforeCommand bool
	Timeout            time.Duration
	Size               session.Size

	CassetteDir string
	Quota       func(string) (cassette.QuotaRecord, error)
	Discovery   func(string) (cassette.DiscoveryRecord, error)

	// Interstitials are transient prompts that can appear before the ready
	// marker or before completion — e.g. Claude Code's "Do you trust the
	// files in this folder?" dialog when the harness is launched in a
	// not-yet-trusted directory (every fresh execute-bead worktree). When the
	// emulated screen matches an interstitial, the driver sends its response
	// once and keeps waiting for the real ready/done markers, so a blocking
	// prompt no longer stalls discovery/quota probes into a timeout.
	Interstitials []Interstitial
}

// Interstitial is a prompt/response pair the driver auto-handles while waiting.
type Interstitial struct {
	// Name uniquely identifies the interstitial so it is answered at most once.
	Name string
	// Match reports whether the current screen is showing this prompt.
	Match func(screen string) bool
	// Send is the byte sequence written to the PTY to dismiss the prompt
	// (e.g. "\r" to accept the highlighted default).
	Send []byte
}

type Result struct {
	Text        string
	CassetteDir string
	Status      Status
}

func Run(ctx context.Context, cfg Config) (Result, error) {
	cfg = defaultConfig(cfg)
	if cfg.Binary == "" {
		return Result{}, &ProbeError{Status: StatusUnavailable, Reason: "quota probe binary is empty"}
	}
	binaryPath, err := exec.LookPath(cfg.Binary)
	if err != nil {
		return Result{}, &ProbeError{Status: StatusUnavailable, Reason: cfg.Binary + " not found in PATH", Err: err}
	}
	if ctx == nil {
		ctx = context.Background()
	}
	if cfg.BinaryVersion == "" {
		cfg.BinaryVersion = "unknown"
		if shouldProbeBinaryVersion(cfg.HarnessName, binaryPath) {
			cfg.BinaryVersion = detectBinaryVersion(ctx, binaryPath)
		}
	}
	ctx, cancel := context.WithTimeout(ctx, cfg.Timeout)
	defer cancel()

	recordDir, commitDir, err := prepareRecordDir(cfg.CassetteDir)
	if err != nil {
		return Result{}, &ProbeError{Status: StatusError, Reason: "prepare quota cassette", Err: err}
	}
	var rec *cassette.Recorder
	if recordDir != "" {
		rec, err = cassette.Create(recordDir, manifestFor(cfg))
		if err != nil {
			cleanupRecordDir(recordDir, commitDir)
			return Result{}, &ProbeError{Status: StatusError, Reason: "create quota cassette", Err: err}
		}
	}

	emu := terminal.New(terminal.Size{Rows: int(cfg.Size.Rows), Cols: int(cfg.Size.Cols)})
	s, err := session.Start(ctx, binaryPath, cfg.Args, cfg.Workdir, probeEnv(cfg.Env), cfg.Size, session.WithTimeout(cfg.Timeout), session.WithBufferSize(4096))
	if err != nil {
		closeDiscard(rec)
		cleanupRecordDir(recordDir, commitDir)
		return Result{}, classifyFailure(cfg.HarnessName, "", err)
	}

	run := &runState{
		session:  s,
		rec:      rec,
		emu:      emu,
		size:     terminal.Size{Rows: int(cfg.Size.Rows), Cols: int(cfg.Size.Cols)},
		scrubber: scrubberFor(cfg),
		done:     make(chan struct{}),
	}
	go run.recordOutput()

	result, err := run.drive(ctx, cfg)
	status := session.ExitStatus{}
	if err != nil {
		_ = s.Kill()
		status = s.Wait()
		select {
		case <-run.done:
		case <-time.After(5 * time.Second):
			_ = s.Close()
		}
		closeDiscard(rec)
		cleanupRecordDir(recordDir, commitDir)
		return Result{}, classifyFailure(cfg.HarnessName, run.screen(), err)
	}
	status = stopSession(s, 5*time.Second)
	finishErr := run.finish(status, cfg)
	if finishErr != nil {
		closeDiscard(rec)
		cleanupRecordDir(recordDir, commitDir)
		return Result{}, &ProbeError{Status: StatusError, Reason: "finish quota probe", Err: finishErr}
	}
	if rec != nil {
		if err := commitRecordDir(recordDir, commitDir); err != nil {
			cleanupRecordDir(recordDir, commitDir)
			return Result{}, &ProbeError{Status: StatusError, Reason: "commit quota cassette", Err: err}
		}
		result.CassetteDir = commitDir
	}
	result.Status = StatusOK
	return result, nil
}

func defaultConfig(cfg Config) Config {
	if cfg.HarnessName == "" {
		cfg.HarnessName = cfg.Binary
	}
	if cfg.Timeout <= 0 {
		cfg.Timeout = 30 * time.Second
	}
	if cfg.Size.Rows == 0 {
		cfg.Size.Rows = 50
	}
	if cfg.Size.Cols == 0 {
		cfg.Size.Cols = 220
	}
	return cfg
}

package codex

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"os"
	osexec "os/exec"
	"strings"
	"syscall"
	"time"

	"github.com/easel/fizeau/internal/harnesses"
	"github.com/easel/fizeau/internal/modelcatalog"
)

const defaultEventBuffer = 64

// Fallback only: unpinned runs resolve through model discovery first.
const fallbackDefaultModel = "gpt-5.4"

// Runner is the subprocess-backed codex harness. It launches codex in
// exec --json mode, parses each JSONL line into harness Events, and emits
// a final Event when the subprocess exits.
type Runner struct {
	// Binary is the absolute path to the codex executable. When empty the
	// runner resolves "codex" via PATH at Execute time.
	Binary string

	// BaseArgs is prepended to the per-request argument list.
	// Codex default: ["exec", "--json"]
	BaseArgs []string

	// PromptMode controls how the prompt is delivered:
	//   "arg" (default) — prompt is appended as the final positional argument
	//   "stdin"         — prompt is piped on stdin
	PromptMode string

	// EventBuffer overrides the per-Execute channel buffer size.
	EventBuffer int

	// DiscoveryCache overrides model/reasoning discovery evidence in tests.
	DiscoveryCache *harnesses.ModelDiscoveryCache
}

// Info returns identity + capability metadata for this harness.
func (r *Runner) Info() harnesses.HarnessInfo {
	info := harnesses.HarnessInfo{
		Name:                 "codex",
		Type:                 "subprocess",
		IsLocal:              false,
		IsSubscription:       true,
		AutoRoutingEligible:  true,
		ExactPinSupport:      true,
		DefaultModel:         harnesses.ResolveRunnerModel("codex", modelcatalog.SurfaceCodex, "", fallbackDefaultModel).ResolvedModel,
		SupportedPermissions: []string{"safe", "supervised", "unrestricted"},
		SupportedReasoning:   []string{"low", "medium", "high", "xhigh", "max"},
		CostClass:            "medium",
	}
	path := r.Binary
	if path == "" {
		if resolved, err := osexec.LookPath("codex"); err == nil {
			path = resolved
		}
	}
	if path != "" {
		info.Path = path
		info.Available = true
	} else {
		info.Error = "codex binary not found in PATH"
	}
	return info
}

// HealthCheck verifies the codex binary is present.
func (r *Runner) HealthCheck(ctx context.Context) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	path := r.Binary
	if path == "" {
		resolved, err := osexec.LookPath("codex")
		if err != nil {
			return fmt.Errorf("codex binary not found: %w", err)
		}
		path = resolved
	}
	st, err := os.Stat(path)
	if err != nil {
		return fmt.Errorf("stat codex binary: %w", err)
	}
	if st.IsDir() {
		return fmt.Errorf("codex binary path is a directory: %s", path)
	}
	return nil
}

// Execute runs one resolved request through the codex CLI and emits
// JSONL-derived events on the returned channel.
func (r *Runner) Execute(ctx context.Context, req harnesses.ExecuteRequest) (<-chan harnesses.Event, error) {
	binary := r.Binary
	if binary == "" {
		resolved, err := osexec.LookPath("codex")
		if err != nil {
			return nil, fmt.Errorf("codex binary not found: %w", err)
		}
		binary = resolved
	}

	bufSize := r.EventBuffer
	if bufSize <= 0 {
		bufSize = defaultEventBuffer
	}

	out := make(chan harnesses.Event, bufSize)
	go r.run(ctx, binary, req, out)
	return out, nil
}

func (r *Runner) run(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event) {
	defer close(out)

	start := time.Now()
	var seq int64

	agg, exitCode, stderr, runErr, status := r.runStreaming(ctx, binary, req, out, &seq)

	final := harnesses.FinalData{
		Status:     status,
		ExitCode:   exitCode,
		DurationMS: time.Since(start).Milliseconds(),
	}
	reasoningResolution := harnesses.ResolveRunnerReasoningWithCache(r.DiscoveryCache, "codex", req.Reasoning)
	if harnesses.ShouldEmitRunnerReasoningResolution(reasoningResolution) {
		final.Reasoning = &reasoningResolution
	}
	if runErr != nil && status != "success" {
		final.Error = runErr.Error()
	} else if stderr != "" && status != "success" {
		final.Error = trimErrorBlob(stderr)
	}
	if agg != nil {
		final.FinalText = agg.FinalText
		final.Usage, final.Warnings = harnesses.ResolveFinalUsage(agg.UsageSources)
		agg.writeTokenCountQuotaCache()
	}

	finalRaw, err := json.Marshal(final)
	if err != nil {
		finalRaw = []byte(`{"status":"failed","error":"marshal final event"}`)
	}
	ev := harnesses.Event{
		Type:     harnesses.EventTypeFinal,
		Sequence: seq,
		Time:     time.Now().UTC(),
		Metadata: req.Metadata,
		Data:     finalRaw,
	}
	select {
	case out <- ev:
	case <-time.After(time.Second):
	}
}

func (a *streamAggregate) writeTokenCountQuotaCache() {
	if a == nil || len(a.TokenCountRateLimits) == 0 {
		return
	}
	var newest *codexQuotaSnapshot
	for _, evidence := range a.TokenCountRateLimits {
		fallback := time.Now().UTC()
		snapshot, ok := codexQuotaSnapshotFromTokenCountRateLimits(evidence.CapturedAt, fallback, evidence.RateLimits)
		if !ok {
			continue
		}
		snapshot.Source = "codex_exec_token_count"
		if newest == nil || snapshot.CapturedAt.After(newest.CapturedAt) {
			newest = snapshot
		}
	}
	if newest == nil {
		return
	}
	path, err := codexQuotaCachePath()
	if err != nil {
		return
	}
	_ = writeCodexQuota(path, *newest)
}

func (r *Runner) runStreaming(ctx context.Context, binary string, req harnesses.ExecuteRequest, out chan<- harnesses.Event, seq *int64) (agg *streamAggregate, exitCode int, stderr string, runErr error, status string) {
	base := r.BaseArgs
	if base == nil {
		base = []string{"exec", "--json"}
	}
	args := append([]string{}, base...)
	modelResolution := harnesses.ResolveRunnerModelWithCache(r.DiscoveryCache, "codex", modelcatalog.SurfaceCodex, req.Model, fallbackDefaultModel)
	reasoningResolution := harnesses.ResolveRunnerReasoningWithCache(r.DiscoveryCache, "codex", req.Reasoning)

	// Permission args: unrestricted adds --dangerously-bypass-approvals-and-sandbox
	if req.Permissions == "unrestricted" {
		args = append(args, "--dangerously-bypass-approvals-and-sandbox")
	}

	// WorkDir flag: -C <dir>
	if req.WorkDir != "" {
		args = append(args, "-C", req.WorkDir)
	}

	// Model flag: -m <model>
	if modelResolution.ResolvedModel != "" {
		args = append(args, "-m", modelResolution.ResolvedModel)
	}

	// Reasoning flag: -c reasoning.effort=<reasoning>
	if value := reasoningResolution.ResolvedReasoning; value != "" {
		args = append(args, "-c", fmt.Sprintf("reasoning.effort=%s", value))
	}

package cmd

// run_cmd_test.go verifies ddx-0248f921 AC:
//   - ddx run --help exits 0 and describes the layer-1 command.
//   - ddx run forwards harness/provider/model/profile to Execute.
