// TestMain clears all GIT_* environment variables before running tests so
// that tests invoking git commands operate on their own temp-dir repositories
// rather than any repository inherited from a hook invocation (e.g. GIT_DIR
// set by lefthook during pre-commit). Prefix scrub is important — lefthook
// sets GIT_AUTHOR_NAME, GIT_COMMITTER_EMAIL, GIT_CONFIG_PARAMETERS etc. that
// also leak into test subprocesses and corrupt the shared repo config.
func TestMain(m *testing.M) {
	for _, kv := range os.Environ() {
		if strings.HasPrefix(kv, "GIT_") {
			if idx := strings.IndexByte(kv, '='); idx >= 0 {
				_ = os.Unsetenv(kv[:idx])
			}
		}
	}
	// Keep cmd tests hermetic. Background update checks can outlive a single
	// test and write into another test's temp HOME/TMPDIR, which makes temp-dir
	// cleanup flaky under the full suite.
	cleanupTemp := isolateCmdTestTempRoot()
	code := m.Run()
	cleanupTemp()
	os.Exit(code)
}

func isolateCmdTestTempRoot() func() {
	tempRoot, err := os.MkdirTemp("", "ddx-cmd-tests-*")
	if err != nil {
		return func() {}
	}
	oldTmpDir, hadTmpDir := os.LookupEnv("TMPDIR")
	oldTmp, hadTmp := os.LookupEnv("TMP")
	oldPath, hadPath := os.LookupEnv("PATH")
	oldXDGCache, hadXDGCache := os.LookupEnv("XDG_CACHE_HOME")
	oldXDG, hadXDG := os.LookupEnv("XDG_DATA_HOME")
	oldHome, hadHome := os.LookupEnv("HOME")
	oldFizeauCache, hadFizeauCache := os.LookupEnv("FIZEAU_CACHE_DIR")
	oldDisableUpdate, hadDisableUpdate := os.LookupEnv("DDX_DISABLE_UPDATE_CHECK")
	homeDir := filepath.Join(tempRoot, "home")
	_ = os.MkdirAll(homeDir, 0o755)
	if _, err := installCmdTestHermeticEnv(homeDir, os.Setenv); err != nil {
		_ = os.RemoveAll(tempRoot)
		return func() {}
	}
	_ = os.Setenv("TMPDIR", tempRoot)
	_ = os.Setenv("TMP", tempRoot)
	return func() {
		if hadTmpDir {
			_ = os.Setenv("TMPDIR", oldTmpDir)
		} else {
			_ = os.Unsetenv("TMPDIR")
		}
		if hadTmp {
			_ = os.Setenv("TMP", oldTmp)
		} else {
			_ = os.Unsetenv("TMP")
		}
		if hadPath {
			_ = os.Setenv("PATH", oldPath)
		} else {
			_ = os.Unsetenv("PATH")
		}
		if hadXDGCache {
			_ = os.Setenv("XDG_CACHE_HOME", oldXDGCache)
		} else {
			_ = os.Unsetenv("XDG_CACHE_HOME")
		}
		if hadXDG {
			_ = os.Setenv("XDG_DATA_HOME", oldXDG)
		} else {
			_ = os.Unsetenv("XDG_DATA_HOME")
		}
		if hadHome {
			_ = os.Setenv("HOME", oldHome)
		} else {
			_ = os.Unsetenv("HOME")
		}
		if hadFizeauCache {
			_ = os.Setenv("FIZEAU_CACHE_DIR", oldFizeauCache)
		} else {
			_ = os.Unsetenv("FIZEAU_CACHE_DIR")
		}
		if hadDisableUpdate {
			_ = os.Setenv("DDX_DISABLE_UPDATE_CHECK", oldDisableUpdate)
		} else {
			_ = os.Unsetenv("DDX_DISABLE_UPDATE_CHECK")
		}
		_ = os.RemoveAll(tempRoot)
	}
}

type cmdTestEnvSetter func(string, string) error

func installCmdTestHermeticEnv(root string, setenv cmdTestEnvSetter) (string, error) {
	if root == "" {
		return "", fmt.Errorf("cmd test hermetic root is empty")
	}

	cacheHome := filepath.Join(root, ".cache")
	dataHome := filepath.Join(root, ".local", "share")
	fizeauCache := filepath.Join(cacheHome, "fizeau")
	fakeBin := filepath.Join(root, ".cmd-bin")

	for _, dir := range []string{cacheHome, dataHome, fizeauCache, fakeBin} {
		if err := os.MkdirAll(dir, 0o755); err != nil {
			return "", err
		}
	}

	for _, name := range []string{"codex", "claude", "gemini"} {
		if err := writeCmdExecutable(filepath.Join(fakeBin, name), providerDiscoveryShim(name)); err != nil {
			return "", err
		}
	}

	path := fakeBin
	if current := os.Getenv("PATH"); current != "" {
		path += string(os.PathListSeparator) + current
	}

	for _, kv := range []struct {
		key   string
		value string
	}{
		{key: "HOME", value: root},
		{key: "XDG_CACHE_HOME", value: cacheHome},
		{key: "XDG_DATA_HOME", value: dataHome},
		{key: "FIZEAU_CACHE_DIR", value: fizeauCache},
		{key: "PATH", value: path},
	} {
		if err := setenv(kv.key, kv.value); err != nil {
			return "", err
		}
	}

	if err := setenv("DDX_DISABLE_UPDATE_CHECK", "1"); err != nil {
		return "", err
	}

	return fakeBin, nil
}

func writeCmdExecutable(path, body string) error {
	return os.WriteFile(path, []byte(body), 0o755)
}

