func ensureProjectGitignoreRules(workingDir string, rules []string) error {
	if len(rules) == 0 {
		return nil
	}
	path := filepath.Join(workingDir, ".gitignore")
	var content string
	if raw, err := os.ReadFile(path); err == nil {
		content = string(raw)
	} else if !os.IsNotExist(err) {
		return err
	}

	trimmed := strings.TrimRight(content, "\n")
	var missing []string
	for _, rule := range rules {
		rule = strings.TrimSpace(rule)
		if rule == "" || containsExactLine(trimmed, rule) {
			continue
		}
		missing = append(missing, rule)
	}
	if len(missing) == 0 {
		return nil
	}

	updated := trimmed
	if updated != "" {
		updated += "\n"
	}
	updated += "# DDx runtime scratch\n"
	for _, rule := range missing {
		updated += rule + "\n"
	}
	return os.WriteFile(path, []byte(updated), 0o644)
}

func untrackLegacyRunStateFiles(ctx context.Context, workingDir string) error {
	if workingDir == "" {
		return nil
	}
	if out, err := gitpkg.Command(ctx, workingDir, "rev-parse", "--is-inside-work-tree").Output(); err != nil || strings.TrimSpace(string(out)) != "true" {
		return nil
	}
	lsCmd := gitpkg.Command(ctx, workingDir, "ls-files", "-z", "--", ".ddx/run-state.json", ".ddx/run-state")
	lsOut, err := lsCmd.Output()
	if err != nil {
		return err
	}
	if len(lsOut) == 0 {
		return nil
	}
	rmCmd := gitpkg.Command(ctx, workingDir, "rm", "--cached", "-r", "-f", "-q", "--ignore-unmatch", "--", ".ddx/run-state.json", ".ddx/run-state")
	if out, err := rmCmd.CombinedOutput(); err != nil {
		msg := strings.TrimSpace(string(out))
		if msg == "" {
			return err
		}
		return fmt.Errorf("%s: %w", msg, err)
	}
	return nil
}

